const policies = $input.first().json.data || [];
const inflate = $node.Config.json.values.inflationAdjustment;
const inflationFactor = inflate ? 1.08 : 1.0;
const gaps = [];

for (const policy of policies) {
  const premium = policy.premium || 0;
  const limits = policy.limits || '';

  // Parse limits (simplified — real implementation would parse the full limits string)
  const limitValue = parseInt(limits.replace(/[^0-9]/g, '')) || premium * 100;
  const estimatedReplacement = Math.round(limitValue * inflationFactor * 1.15);

  if (estimatedReplacement > limitValue * 1.1) {
    const gapAmount = estimatedReplacement - limitValue;
    gaps.push({ json: {
      ...policy,
      currentLimits: '$' + limitValue.toLocaleString(),
      replacementCost: '$' + estimatedReplacement.toLocaleString(),
      gapAmount: '$' + gapAmount.toLocaleString(),
      gapPercent: Math.round((gapAmount / limitValue) * 100),
      recommendation: `Increase limits from $${limitValue.toLocaleString()} to $${estimatedReplacement.toLocaleString()} to match current replacement value`
    }});
  }
}

return gaps.length > 0 ? gaps : [{ json: { _empty: true, summary: 'No coverage gaps detected' } }];

const items = $input.all();
const gapCount = items.filter(i => !i.json._empty).length;
return [{ json: { summary: `Coverage gap analysis: ${gapCount} underinsured policies identified out of ${items.length} analyzed`, gapsFound: gapCount, policiesAnalyzed: items.length, status: 'success' } }];
